+function isClawSweeperReviewMarkerComment(comment: JsonValue) {
+  const body = String(comment.body ?? "");
+  return (
+    body.includes("clawsweeper-verdict:") ||
+    body.includes("clawsweeper-finding:") ||
+    body.includes("clawsweeper-review item=")
   );
 }

